const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Verwalte den Linux-Host des Druckers — prüfe seinen Zustand und den des Betriebssystems und steuere seine Hintergrunddienste. Datenträger-Bereinigung und Systemeinstellungen folgen in späteren Phasen."}},view:{monitor:{t:0,b:{t:2,i:[{t:3}],s:"Monitor"}},services:{t:0,b:{t:2,i:[{t:3}],s:"Dienste"}},cleanup:{t:0,b:{t:2,i:[{t:3}],s:"Bereinigung"}}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Was ist das?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind läuft auf dem kleinen Linux-Computer des Druckers (dem Host). Dieses Panel liest dessen Live-Zustand und Betriebssystem-Status, damit du Probleme erkennst — eine überhitzte CPU, eine volle Festplatte, eine nicht synchronisierte Uhr — ohne ein Terminal zu öffnen, und lässt dich die Hintergrunddienste steuern, die er ausführt."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Lies die Karten für CPU-Temperatur, Speicher, Datenträger und Netzwerk auf einen Blick."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Beobachte die Tabelle der Top-Prozesse, um zu sehen, was die CPU gerade auslastet."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Lass die automatische Aktualisierung für eine Live-Ansicht an, oder schalte sie aus und aktualisiere manuell."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Hier verwendete Begriffe"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"Den Monitor lesen"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Alles hier ist schreibgeschützt. Balken werden ab 75 % bernsteinfarben und ab 90 % rot. Die CPU-Temperatur wird bei 70 °C bernsteinfarben und bei 80 °C rot. Die Drosselungs-Warnung erscheint nur auf Boards, die sie melden (hauptsächlich Raspberry Pi)."}}},services:{title:{t:0,b:{t:2,i:[{t:3}],s:"Dienste verwalten"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Jede Zeile ist ein systemd-Dienst. Klicke einen an, um ihn zu starten/stoppen/neu zu starten, beim Booten zu aktivieren/deaktivieren, zu maskieren, sein Protokoll zu lesen oder — bei selbst installierten Diensten — seine Unit-Datei zu löschen. Einen Dienst zu stoppen oder zu deaktivieren erfordert eine Bestätigung. Kritische und geschützte Dienste sind markiert; geschützte (wie SSH und dieses Panel) lassen sich nicht stoppen, damit du dich nicht aussperrst."}}},cleanup:{title:{t:0,b:{t:2,i:[{t:3}],s:"Speicherplatz freigeben"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Jede Zeile wird zuerst gescannt, um zu zeigen, wie viel sie freigeben würde. Hake die zu leerenden an und bestätige. Nur regenerierbare Daten werden angeboten — der apt-Download-Cache, das alte systemd-Journal, ~/.cache, deine alten /tmp-Dateien und rotierte (nicht aktive) Protokolle. Deine G-Codes, Zeitraffer und Konfigurationen werden nie angetastet."}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Der kleine Linux-Computer (z. B. ein Raspberry Pi oder BTT CB1), der Klipper, Moonraker und FilaMind ausführt — getrennt von den Mikrocontrollern des Druckers."}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"Lastdurchschnitt"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Wie viele Prozesse auf Ausführung warteten, gemittelt über 1 / 5 / 15 Minuten. Grob: ein Wert nahe der Kernzahl bedeutet, die CPU ist beschäftigt; deutlich darüber bedeutet Überlastung."}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Festplattenspeicher, der als Überlauf genutzt wird, wenn der RAM voll ist. Starke Swap-Nutzung verlangsamt den Host — ein Zeichen für Speichermangel."}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"Drosselung"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Wenn das Board die Geschwindigkeit reduziert, um sich selbst zu schützen — meist wegen einer schwachen Stromversorgung (Unterspannung) oder Überhitzung. Wird hauptsächlich beim Raspberry Pi gemeldet."}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / Uhr-Synchronisation"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Das Network Time Protocol hält die Host-Uhr genau. Eine nicht synchronisierte Uhr kann Zeitraffer, Protokolle und TLS-Zertifikate stören."}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"Locale"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Die Sprach- und Tastaturlayout-Einstellungen des Hosts, die das Betriebssystem für Text, Datumsangaben und das Konsolen-Tastaturlayout nutzt."}}},service:{term:{t:0,b:{t:2,i:[{t:3}],s:"Dienst (Unit)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein von systemd verwaltetes Hintergrundprogramm — Klipper, Moonraker, der Webcam-Streamer und der Netzwerk-Stack laufen alle als Dienste."}}},enabled:{term:{t:0,b:{t:2,i:[{t:3}],s:"Aktiviert / deaktiviert"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ob ein Dienst beim Booten automatisch startet. „enabled“ startet beim Booten; „disabled“ nicht; „static“ wird nur von einem anderen Dienst gestartet."}}},mask:{term:{t:0,b:{t:2,i:[{t:3}],s:"Maskieren"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Eine stärkere Form des Deaktivierens — der Dienst kann gar nicht gestartet werden (auch nicht von einem anderen Dienst), bis er demaskiert wird. Mit Vorsicht verwenden."}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"Aktualisieren"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"Auto-Aktualisierung"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Host-Status wird gelesen…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"Hostname"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"Betriebssystem"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"Kernel"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"Laufzeit"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"CPU"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"Temperatur"}},load:{t:0,b:{t:2,i:[{t:3}],s:"Last (1·5·15 Min)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"Kerne"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"Gedrosselt"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"Speicher"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"RAM"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"Datenträger"}},network:{t:0,b:{t:2,i:[{t:3}],s:"Netzwerk"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"Schnittstelle"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"IP-Adresse"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"WLAN"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"Signal"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"Zeit & Locale"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"Zeitzone"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"Uhr-Synchronisation"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"Synchronisiert"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"Wird synchronisiert…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"Aus"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Sprache"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"Tastaturlayout"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"Top-Prozesse"}},command:{t:0,b:{t:2,i:[{t:3}],s:"Befehl"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"CPU %"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"RAM %"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"PID"}}},services:{warning:{t:0,b:{t:2,i:[{t:3}],s:"Den falschen Dienst zu stoppen oder zu deaktivieren kann den Drucker offline nehmen. Kritische Dienste sind markiert; geschützte lassen sich nicht stoppen."}},search:{t:0,b:{t:2,i:[{t:3}],s:"Dienste suchen…"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Aktualisieren"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Dienste werden aufgelistet…"}},loadingDetail:{t:0,b:{t:2,i:[{t:3}],s:"Dienst wird gelesen…"}},loadingLogs:{t:0,b:{t:2,i:[{t:3}],s:"Protokoll wird gelesen…"}},summary:{t:0,b:{t:2,i:[{t:4,k:"total"},{t:3,v:" Dienste · "},{t:4,k:"active"},{t:3,v:" aktiv · "},{t:4,k:"failed"},{t:3,v:" fehlgeschlagen"}]}},filter:{all:{t:0,b:{t:2,i:[{t:3}],s:"Alle"}},active:{t:0,b:{t:2,i:[{t:3}],s:"Aktiv"}},inactive:{t:0,b:{t:2,i:[{t:3}],s:"Inaktiv"}},failed:{t:0,b:{t:2,i:[{t:3}],s:"Fehlgeschlagen"}},enabled:{t:0,b:{t:2,i:[{t:3}],s:"Aktiviert"}}},stateActive:{t:0,b:{t:2,i:[{t:3}],s:"Aktiv"}},stateInactive:{t:0,b:{t:2,i:[{t:3}],s:"Inaktiv"}},stateFailed:{t:0,b:{t:2,i:[{t:3}],s:"Fehlgeschlagen"}},critical:{t:0,b:{t:2,i:[{t:3}],s:"Kritisch"}},protected:{t:0,b:{t:2,i:[{t:3}],s:"Geschützt"}},state:{t:0,b:{t:2,i:[{t:3}],s:"Status"}},startup:{t:0,b:{t:2,i:[{t:3}],s:"Autostart"}},unitFile:{t:0,b:{t:2,i:[{t:3}],s:"Unit-Datei"}},action:{start:{t:0,b:{t:2,i:[{t:3}],s:"Starten"}},stop:{t:0,b:{t:2,i:[{t:3}],s:"Stoppen"}},restart:{t:0,b:{t:2,i:[{t:3}],s:"Neu starten"}},enable:{t:0,b:{t:2,i:[{t:3}],s:"Aktivieren"}},disable:{t:0,b:{t:2,i:[{t:3}],s:"Deaktivieren"}},mask:{t:0,b:{t:2,i:[{t:3}],s:"Maskieren"}},unmask:{t:0,b:{t:2,i:[{t:3}],s:"Demaskieren"}}},actionOk:{t:0,b:{t:2,i:[{t:4,k:"action"},{t:3,v:" erledigt."}]}},confirmAction:{t:0,b:{t:2,i:[{t:3,v:"„"},{t:4,k:"name"},{t:3,v:"“ "},{t:4,k:"action"},{t:3,v:"?"}]}},confirmYes:{t:0,b:{t:2,i:[{t:3}],s:"Ja, ausführen"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Abbrechen"}},deleteUnit:{t:0,b:{t:2,i:[{t:3}],s:"Unit-Datei löschen…"}},deletePrompt:{t:0,b:{t:2,i:[{t:3,v:"Dies entfernt die Unit-Datei dauerhaft. Tippe „"},{t:4,k:"name"},{t:3,v:"“ zur Bestätigung."}]}},deleteConfirm:{t:0,b:{t:2,i:[{t:3}],s:"Endgültig löschen"}},deleted:{t:0,b:{t:2,i:[{t:3}],s:"Unit-Datei entfernt."}},logs:{t:0,b:{t:2,i:[{t:3}],s:"Letztes Protokoll"}},noLogs:{t:0,b:{t:2,i:[{t:3}],s:"Keine Protokollausgabe."}}},cleanup:{subtitle:{t:0,b:{t:2,i:[{t:3}],s:"Hake an, was entfernt werden soll, dann bereinige. Nur Caches und alte Protokolle — Drucke und Konfigurationen bleiben sicher."}},rescan:{t:0,b:{t:2,i:[{t:3}],s:"Neu scannen"}},scanning:{t:0,b:{t:2,i:[{t:3}],s:"Datenträger wird gescannt…"}},na:{t:0,b:{t:2,i:[{t:3}],s:"n. v."}},items:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" Dateien"}]}},freed:{t:0,b:{t:2,i:[{t:4,k:"size"},{t:3,v:" freigegeben."}]}},selectedTotal:{t:0,b:{t:2,i:[{t:3,v:"Ausgewählt: "},{t:4,k:"size"}]}},clean:{t:0,b:{t:2,i:[{t:3}],s:"Auswahl bereinigen"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Die ausgewählten Elemente löschen?"}},confirmYes:{t:0,b:{t:2,i:[{t:3}],s:"Ja, bereinigen"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Abbrechen"}},running:{t:0,b:{t:2,i:[{t:3}],s:"Wird bereinigt…"}},targets:{apt:{label:{t:0,b:{t:2,i:[{t:3}],s:"Paket-Cache"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Heruntergeladene .deb-Installationsdateien, die apt nicht mehr braucht."}}},journal:{label:{t:0,b:{t:2,i:[{t:3}],s:"System-Journal"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Alte systemd-Protokolle — auf die letzten 50 MB verkleinert."}}},cache:{label:{t:0,b:{t:2,i:[{t:3}],s:"Benutzer-Cache"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Regenerierbare Dateien in ~/.cache (Vorschaubilder, pip usw.)."}}},tmp:{label:{t:0,b:{t:2,i:[{t:3}],s:"Temporäre Dateien"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Deine eigenen Dateien in /tmp, älter als ein Tag."}}},logs:{label:{t:0,b:{t:2,i:[{t:3}],s:"Rotierte Protokolle"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Alte, rotierte Klipper/Moonraker-Protokolle (das aktive bleibt erhalten)."}}}}}}};export{t as default};
